final:
module top_module(
    input CLK,
    input D,
    input PRE,
    input CLR,
    output reg Q,
    output reg Q_bar
);always @ (posedge CLK) begin
    if (PRE) begin
        Q <= 1'b1;
    end else if (CLR) begin
        Q <= 1'b0;
    end else begin
        Q <= D;
    end
end

wire not_Q = ~Q;
assign Q_bar = not_Q;

endmodule
